@property(strong, nonatomic) NSMutableArray *observerTokens; // 用于存储多个观察者的令牌
@property(strong, nonatomic) UIViewController *originVC; // 调用弹窗的原始界面（用于多弹窗时，后续弹窗的出现场景判断）
@property(strong, nonatomic) NSDictionary *storePopupData;  // 暂存的弹窗数据，待相关事件结束后展示
