- (void)showPopup {
    if (!self.popups.count) return;
    void (^showPopupBlock)(void) = ^{
        UIViewController *rootVC = [WBAppManager getUIApplicationRootViewController];
        UIViewController *hostVC = rootVC.presentedViewController ?: rootVC;
        if ([hostVC isKindOfClass:[UIAlertController class]]) return;
        WBNoticeModel *notice = self.popups.firstObject;
        UIViewController *popupVC = [self getPopupVCWithNotice:notice];
        [hostVC presentViewController:popupVC animated:false completion:nil];
        if (notice.popupId != -1) {
            [WBNetworkManager.defaultManager sendPopupId:notice.popupId];   // 上报默认弹窗已展示
        } else if(notice.scheduleId != -1) {
            [WBNetworkManager.defaultManager sendScheduleId:notice.scheduleId]; // 上报优惠券默认弹窗已展示
        }
        self.presentedPopup = popupVC;
        self.notice = notice;
        [self.popups popFirstObject];
    };
    if (self.presentedPopup) {
        [self.presentedPopup dismissViewControllerAnimated:NO completion:showPopupBlock];
    } else {
        showPopupBlock();
    }
}

- (UIViewController *)getPopupVCWithNotice:(WBNoticeModel *)notice {
    UIViewController *popupVC = nil;
    if (notice.style == WBNoticeStylePopUp) {
        popupVC = [WBPopupViewController controllerWithNotice:notice];
    } else if (notice.style == WBNoticeStyleSystemAlert) {
        popupVC = [WBPopUpAlertController controllerWithNotice:notice];
    }
    return popupVC;
}

- (void)dismissPopup {
    [self.presentedPopup dismissViewControllerAnimated:NO completion:^{
        [[NSNotificationCenter defaultCenter] postNotificationName:WBPopupDismissNotification object:nil];
        if (self.popups.count > 0) {
            [self showPopup];
        } else {
            self.presentedPopup = nil;
            self.notice = nil;
        }
    }];
}

- (void)operationClicked:(WBRichMessageLinkModel *)operation style:(WBNoticeStyle)style {
    [WBNetworkManager.defaultManager sendNoticeEvent:style richMessageLinkId:operation.richMessageLinkId popupName:self.notice.name eventName:operation.label];
    operation.action = [self getActionBlock:operation];
    if (operation.action) {
        operation.action();
    }
    if (operation.postAction) {
        operation.postAction();
    }
    if (operation.isDismissOnTap) {
        [self dismissPopup];
    }
}

- (WBActionBlock)getActionBlock:(WBRichMessageLinkModel *)link{
    @weakify(self)
    WBActionBlock block = NULL;
    switch(link.type) {
        case WBRichMessageLinkTypeArticle:
        case WBRichMessageLinkTypeWebview:
            if (1) {
                block = ^{
                    @strongify(self)
                    WBWebViewController *webVC = [[WBWebViewController alloc] initWithURL:[NSURL URLWithString:link.link]];
                    if ([self.presentedPopup isKindOfClass:[UINavigationController class]]) {
                        [(UINavigationController *)self.presentedPopup pushViewController:webVC animated:YES];
                    } else {
                        [self.presentedPopup dismissViewControllerAnimated:false completion:^{
                            UIViewController *rootVC = [WBAppManager getUIApplicationRootViewController];
                            [rootVC presentViewController:webVC animated:true completion:nil];
                            if (link.isDismissOnTap) return;
                            webVC.dismissBlock = ^{
                                [rootVC presentViewController:self.presentedPopup animated:true completion:nil];
                            };
                        }];
                    }
                };
            }
            break;
        case WBRichMessageLinkTypeAppstoreRate:
            if (1) {
                block = ^{
                    [WBAppManager.sharedManager writeReviewInAppStore:@"popup"];
                };
            }
            break;
        case WBRichMessageLinkTypeDismiss:
            if (1) {
                block = ^{
                    @strongify(self)
                    [self dismissPopup];
                };
            }
            break;
        case WBRichMessageLinkTypeExit:
            if (1) {
                block = ^{
                    exit(0);
                };
            }
            break;
        case WBRichMessageLinkTypeDefault:
            if (self.stashedDefaultHandler) {
                block = self.stashedDefaultHandler;
                self.stashedDefaultHandler = nil;

            }
            break;
        default:
            if (link.generalAction) {
                block = link.generalAction;
            } else {
                NSLog(@"no action defined for operation:%@", link.label);
            }
            break;
    }
    return block;
}

