@property(strong, nonatomic) NSArray<WBVAppModel *> *dualvapps; //可下载的vapp
@property(strong, nonatomic) UIViewController *launchVC;
@property(nonatomic, getter=isLoading) BOOL loading;

@property(nonatomic, strong) UIButton *subscribeButton;
@property(nonatomic, strong) WBHomeInviteView *inviteView;
@property(nonatomic, strong) WBVappCarouselView *vappCarouselView;
@property(nonatomic, strong) UIPageControl *vappPageControl;

@property(nonatomic, getter=isSkipVIPCheckWhenLaunch) BOOL skipVIPCheckWhenLaunch;
@property(nonatomic, getter=isSkipActionRequestWhenLaunch) BOOL skipActionRequestWhenLaunch;
@property(nonatomic, getter=isVappLaunching) BOOL vappLaunching;

@property(strong, nonatomic) WBHomeVipCountDownView *vipCountDownView;  // 会员到期提醒续费视图
@property(strong, nonatomic) UIBarButtonItem *settingBarButtonItem;
@property(strong, nonatomic) UIBarButtonItem *hasUnReadFeedbackBarButtonItem;
@property(strong, nonatomic) UIBarButtonItem *defaultReadFeedbackBarButtonItem;
@property(strong, nonatomic) UIBarButtonItem *leftTitleBarButtonItem;
@property(nonatomic, assign) NSTimeInterval lastHandleNewMsgTimestamp;

@property(nonatomic, assign) BOOL shouldShowIntroMaskWhenReady;

@end

@implementation WBHomeViewController


#pragma mark - Basic

- (void)setLoading:(BOOL)loading {
    if (self.isLoading == loading)
    {
        return;
    }
    _loading = loading;
}

- (NSArray<WBVAppModel *> *)vapps {
    return WBVAppManager.sharedManager.myApps;
}


- (instancetype)init {
    if (self = [super init]) {
        WBVAppModel *whatsAppVApp = nil;
        NSString *whatsAppBundleId = nil;
        for (WBVAppModel *vapp in self.dualvapps) {
            if ([vapp.name isEqualToString:@"WhatsApp"]) {
                whatsAppVApp = vapp;
                whatsAppBundleId = vapp.bundleId;
                break;
            }
        }

        [[NSNotificationCenter defaultCenter] addObserverForName:WBTapMessageInNotification object:nil queue:nil usingBlock:^(NSNotification * _Nonnull notification) {
            NSString *vappBundleId = [notification.userInfo objectForKey:@"vappBundleId"];
            if([vappBundleId isEqual:whatsAppBundleId]) { // 如果点击的是WhatsApp消息，就直接跳转打开WhatsApp
                if ([WBSettingManager sharedManager].IsVIP) {
                    [self onPressVApp:whatsAppVApp isFromWhatsAppMessage:true];
                } else {    // 非VIP不启动WhatsApp
                    return;
                }
            }
        }];
        [[NSNotificationCenter defaultCenter] addObserverForName:WBUpdateExpirationAlertNotification object:nil queue:nil usingBlock:^(NSNotification * _Nonnull notification) {
            [self showHomeVipCountDownView];
        }];
        [[NSNotificationCenter defaultCenter] addObserverForName:WBEnableSecurityLockNotification object:nil queue:nil usingBlock:^(NSNotification * _Nonnull notification) {
            WBVAppModel *vapp = notification.object;
            WBSettingVappPasswordController *settingPasswordVC = [[WBSettingVappPasswordController alloc] initWithVapp:vapp];
            [self.navigationController pushViewController:settingPasswordVC animated:YES];
        }];
        [[NSNotificationCenter defaultCenter] addObserverForName:WBUnreadFeedbacksCheckNotification object:nil queue:nil usingBlock:^(NSNotification * _Nonnull notification) {
            [self handleNewMsgFromFeedbacks];
        }];
        [[NSNotificationCenter defaultCenter] addObserverForName:WBAllReadFeedbacksNotification object:nil queue:nil usingBlock:^(NSNotification * _Nonnull notification) {
            [self handleAllReadFeedbacks];
        }];

    }
    return self;
}


#pragma mark - Lifecycle

- (void)viewDidLoad {
    [super viewDidLoad];
    [self setUpUI];
    [self loadDualApps];

    self.navigationItem.rightBarButtonItems = @[self.settingBarButtonItem, self.defaultReadFeedbackBarButtonItem];

    self.loading = kArrayIsEmpty(WBVAppManager.sharedManager.myApps);

    [NSNotificationCenter.defaultCenter addObserver:self selector:@selector(handleMyVAppClick:) name:WBAddPageClickMyVAppNotification object:nil];
    [NSNotificationCenter.defaultCenter addObserver:self selector:@selector(handleVAppGet:) name:WBGetVAppNotification object:nil];
    [NSNotificationCenter.defaultCenter addObserver:self selector:@selector(handleVAppReserve:) name:WBReserveVAppNotification object:nil];
    [NSNotificationCenter.defaultCenter addObserver:self selector:@selector(handleVAppDownloadError:) name:WBVAppDownloadErrorNotification object:nil];
    [NSNotificationCenter.defaultCenter addObserver:self selector:@selector(handleVAppInstallError:) name:WBVAppInstallErrorNotification object:nil];
    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(customPopupDismissed:) name:CustomPopupDismissedNotification object:nil];  // 接收活动弹窗的通知，将 vapp 的启动状态设置为FALSE。
    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(handleReferralDataUpdated) name:WBReferralDataUpdatedNotification object:nil];
    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(handleAppShareSuccess) name:WBAppShareSuccessNotification object:nil];

    [[WBActionRequestManager sharedManager] requestReportEventWithType:WBActionRequestEventTypePageHomeShow defaultHandler:nil];
    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(handlePopupDismiss) name:WBPopupDismissNotification object:nil];

}

- (void)viewWillAppear:(BOOL)animated {
    [super viewWillAppear:animated];
    [WBEventManager logAppPageShowEvent:@"Home" from:@""];
    // Nav back from passwordvc or other conditions, which indicates password auth failed or other conditions that cause vapp fail to launch.
    [self handleNewMsgFromFeedbacks];   // 查询最新的客服对话消息

    if (self.isVappLaunching) {
        self.vappLaunching = false; // Reset launch status.
    }

    self.navigationItem.title = nil;
    self.navigationItem.leftBarButtonItem = self.leftTitleBarButtonItem;
    UILabel *label = (UILabel *)self.leftTitleBarButtonItem.customView;
    label.text = self.title ?: NSLocalizedString(@"WhatsBox", nil);
    [label sizeToFit];

}

- (void)viewDidAppear:(BOOL)animated {
    [super viewDidAppear:animated];

    // Execute pending route after view is fully displayed
    [self checkAndExecutePendingRoute];

    BOOL notFirst = [[NSUserDefaults standardUserDefaults] boolForKey:@"notFirstLaunch"];
    if (!notFirst) {
        [self showIntroMask];
    }
}

- (void)checkAndExecutePendingRoute {
    NSURL *pendingURL = WBReferralManager.sharedManager.pendingRouteURL;
    NSString *sourceInterface = WBReferralManager.sharedManager.pendingRouteSourceInterface;

    if (pendingURL) {
        dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(0.5 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
            [[WBRouteManager sharedManager] performRoute:pendingURL sourceInterface:sourceInterface];

            // Clear after execution
            WBReferralManager.sharedManager.pendingRouteURL = nil;
            WBReferralManager.sharedManager.pendingRouteSourceInterface = nil;
        });
    }
}

- (void)showIntroMask {

    // 防止重复显示
    if ([self.view viewWithTag:9999]) {
