- (instancetype)initWithDict:(NSDictionary *)dict sourceInterface:(nullable NSString *)sourceInterface {
    if (self = [super init]) {
        NSString *createDateStr = dict[@"created_at"];
        self.createDate = [[NSDateFormatter wb_isoDateFormatter] dateFromString:createDateStr];
        NSDictionary *richMes = dict[@"rich_message"];
        // Set up properties with rich message.
        self.richMessageId = [dict[@"id"] longValue];
        if (richMes) {
            if (richMes[@"name"] != [NSNull null]) {
                self.name = richMes[@"name"];
            }

            if (richMes[@"title"] != [NSNull null]) {
                self.title = richMes[@"title"];
            }

            if (richMes[@"content"] != [NSNull null]) {
                self.content = richMes[@"content"];
            }

            if (richMes[@"image"] && richMes[@"image"] != [NSNull null]) {
                self.imageNameOrUrl = richMes[@"image"];
            }

            if (richMes[@"icon"] && richMes[@"icon"] != [NSNull null]) {
                self.iconURL = richMes[@"icon"];
            }

            if (richMes[@"links"] != [NSNull null]) {
                NSArray *arrayDicts = richMes[@"links"];
                if (arrayDicts.count) {
                    NSMutableArray<WBRichMessageLinkModel *> *arrayOps = [NSMutableArray arrayWithCapacity:arrayDicts.count];
                    for (NSDictionary *dict in arrayDicts) {
                        WBRichMessageLinkModel *op = [[WBRichMessageLinkModel alloc] initWithDict:dict sourceInterface:sourceInterface];
                        [arrayOps addObject:op];
                    }
                    self.operations = arrayOps;
                }
            }
            if (richMes[@"popupId"] && richMes[@"popupId"] != [NSNull null]) {
                self.popupId = [richMes[@"popupId"] intValue];
            } else {
                self.popupId = -1;  // 无效值
            }
            if (richMes[@"scheduleId"] && richMes[@"scheduleId"] != [NSNull null]) {
                self.scheduleId = [richMes[@"scheduleId"] intValue];
            } else {
                self.scheduleId = -1;   // 无效值
            }
        }
    }
    return self;
}

+ (NSArray *)modelsWithDicts:(NSArray<NSDictionary *> *)arrayDict sourceInterface:(nullable NSString *)sourceInterface {
    NSMutableArray *arrayModel = [NSMutableArray arrayWithCapacity:arrayDict.count];
    for (NSDictionary *dict in arrayDict) {
        WBRichMessageModel *model = [[self alloc] initWithDict:dict sourceInterface:sourceInterface];
        [arrayModel addObject:model];
    }
    return arrayModel;
}

- (void)addOperation:(WBRichMessageLinkType)type style:(WBRichMessageLinkStyle)style label:(NSString *)label link:(NSString * _Nullable)link block:(WBActionBlock _Nullable)block {
    if (_operations == nil) {
        _operations = [NSMutableArray array];
    }
    WBRichMessageLinkModel *operation = [[WBRichMessageLinkModel alloc] init];
    operation.type = type;
    operation.style = style;
    operation.label = label;
    operation.link = link;
    operation.postAction = block;
    [self.operations addObject:operation];
}

@end

