 85	- (void)initGeneralAction {
 86	    @weakify(self)
 87	    switch(self.type) {
 88	        case WBRichMessageLinkTypeFAQ:
 89	            // no general action, since action's supported in Support page only
 90	            break;
 91	        case WBRichMessageLinkTypeArticle:
 92	            // no general action, since needs a navigationVC
 93	            break;
 94	        case WBRichMessageLinkTypeWebview:
 95	            if (_generalAction == nil) {
 96	                _generalAction = ^{
 97	                    @strongify(self)
 98	                    [WBAppManager.sharedManager showInWebView:self.link];
 99	                };
100	            }
101	            break;
102	        case WBRichMessageLinkTypeAppstoreRate:
103	            // no general action, since source's required to rate
104	            break;
105	        case WBRichMessageLinkTypeAppstoreInfo:
106	            if (_generalAction == nil) {
107	                _generalAction = ^{
108	                    @strongify(self)
109	                    [WBAppManager.sharedManager viewAppDetailInAppStore:self.link];
110	                };
111	            }
112	            break;
113	        case WBRichMessageLinkTypeAppstoreSearch:
114	            if (_generalAction == nil) {
115	                _generalAction = ^{
116	                    @strongify(self)
117	                    [WBAppManager.sharedManager searchInAppStore:self.link];
118	                };
119	            }
120	            break;
121	        case WBRichMessageLinkTypeSafari:
122	            if (_generalAction == nil) {
123	                _generalAction = ^{
124	                    @strongify(self)
125	                    [WBAppManager.sharedManager openInSafari:self.link];
126	                };
127	            }
128	            break;
129	        case WBRichMessageLinkTypeDismiss:
130	            // no general action, only supported in popup
131	            break;
132	        case WBRichMessageLinkTypeExit:
133	            // no general action, only supported in popup
134	            break;
135	        case WBRichMessageLinkTypeWBRoute:
136	            if (_generalAction == nil) {
137	                _generalAction = ^{
138	                    @strongify(self)
139	                    if (!self.link) return;
140	                    // 添加对self.link的http或https开头的检查
141	                    if ([self.link hasPrefix:@"http://"] || [self.link hasPrefix:@"https://"]) {
142	                        NSLog(@"This is not a route link but a website link!");
143	                        return;
144	                    }
145	                    NSURL *url = [NSURL URLWithString:self.link];
146	                    NSString *triggerId = self.richMessageLinkId ?: (self.bannerId ?: nil);
147	                    if ([url.absoluteString isEqualToString:@"webox:///page/vip"] && triggerId) {
148	                        NSURLComponents *components = [NSURLComponents componentsWithString:url.absoluteString];
149	                        NSMutableArray<NSURLQueryItem *> *queryItems = [components.queryItems mutableCopy] ?: [NSMutableArray new];
150	                        NSURLQueryItem *triggerItem = [NSURLQueryItem queryItemWithName:@"triggerId" value:triggerId];
151	                        [queryItems addObject:triggerItem];
152	                        if (!self.richMessageLinkId && self.bannerId) {
153	                            NSURLQueryItem *sourceItem = [NSURLQueryItem queryItemWithName:@"source" value:@"banner"];
154	                            [queryItems addObject:sourceItem];
155	                        }
156	                        components.queryItems = queryItems;
157	                        url = components.URL;
158	                    }
159	                    dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(0.3 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
160	                        [[WBRouteManager sharedManager] performRoute:url sourceInterface:self.sourceInterface];
161	                    });
162	                };
163	            }
164	            break;
165	        default:
166	            break;
167	    }
168	}
