+ (instancetype)sharedManager {
    static id instance;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        instance = [[WBDynamicPopupResUnzip alloc] init];

        // 添加一个观察者来监听动态弹窗关闭的通知，以便删除前面下载的动态弹窗的资源
        [[NSNotificationCenter defaultCenter] addObserver:instance
                                             selector:@selector(popupManagerDidClose:)
                                                 name:DynamicPopupDismissedNotification
                                               object:nil];
    });
    return instance;
}

- (void)dealloc {
    // 移除观察者
    [[NSNotificationCenter defaultCenter] removeObserver:self];
}

- (void)sendClickEvent {
